import { test, expect, type ElectronApplication, type Page } from '@playwright/test';
import { launchApp, closeApp } from '../electron';

let app: ElectronApplication;
let page: Page;

test.beforeAll(async () => {
  ({ app, page } = await launchApp());
});

test.afterAll(async () => {
  await closeApp(app);
});

test.describe('Switch between sessions', () => {
  test('Create two sessions and switch between them', async () => {
    // Skip when no project exists (clean CI environment)
    const welcomeScreen = page.getByTestId('openmgr-welcome-screen');
    const hasWelcome = await welcomeScreen.isVisible().catch(() => false);
    test.skip(hasWelcome, 'Requires an existing project — welcome screen is showing');
    await page.getByTestId('openmgr-project-new-session').click();
    await expect(page.getByTestId('openmgr-chat-input')).toBeVisible();
    await page.getByTestId('openmgr-chat-input-field').click();
    await page.getByTestId('openmgr-chat-input-field').fill('First session message');
    await page.getByTestId('openmgr-chat-send').click();
    await expect(page.getByText('First session message')).toBeVisible({ timeout: 10000 });
    await page.getByTestId('openmgr-project-new-session').click();
    await expect(page.getByTestId('openmgr-chat-input')).toBeVisible();
  });
});
